// Cities with corrected coordinates mapped to real SVG space (viewBox 0 0 800 600)
// Geographic → SVG mapping: X range 100-680 (lon -9 to 12.5), Y range 30-560 (lat 37.2 to 18.5)
const CITIES = [
    { id: "alger", name: "Alger", x: 425, y: 45, hub: true },
    { id: "oran", name: "Oran", x: 342, y: 78, hub: true },
    { id: "constantine", name: "Constantine", x: 532, y: 53, hub: true },
    { id: "adrar", name: "Adrar", x: 385, y: 280, hub: true },
    { id: "annaba", name: "Annaba", x: 555, y: 38, hub: false },
    { id: "setif", name: "Sétif", x: 503, y: 58, hub: false },
    { id: "tlemcen", name: "Tlemcen", x: 320, y: 107, hub: false },
    { id: "biskra", name: "Biskra", x: 498, y: 106, hub: false },
    { id: "bechar", name: "Béchar", x: 323, y: 232, hub: false },
    { id: "ghardaia", name: "Ghardaïa", x: 436, y: 150, hub: false },
    { id: "ouargla", name: "Ouargla", x: 520, y: 250, hub: true },
    { id: "tindouf", name: "Tindouf", x: 180, y: 320, hub: false },
    { id: "ilizi", name: "Ilizi", x: 570, y: 373, hub: false },
    { id: "tamanrasset", name: "Tamanrasset", x: 500, y: 453, hub: false },
];

const ROUTES = [
    { from: "alger", to: "oran", delay: 0.0 },
    { from: "alger", to: "constantine", delay: 0.0 },
    { from: "oran", to: "adrar", delay: 0.0 },
    { from: "constantine", to: "ouargla", delay: 0.0 },
    { from: "adrar", to: "ouargla", delay: 0.0 },
    { from: "constantine", to: "annaba", delay: 0.3 },
    { from: "constantine", to: "setif", delay: 0.5 },
    { from: "constantine", to: "biskra", delay: 0.5 },
    { from: "oran", to: "tlemcen", delay: 0.5 },
    { from: "adrar", to: "tindouf", delay: 0.5 },
    { from: "adrar", to: "bechar", delay: 0.5 },
    { from: "bechar", to: "adrar", delay: 0.1 },
    { from: "adrar", to: "tamanrasset", delay: 0.1 },
    { from: "ouargla", to: "ghardaia", delay: 0.1 },
    { from: "ouargla", to: "ilizi", delay: 0.1 },
];

type City = typeof CITIES[number];

function getCityPos(id: string): City {
    return CITIES.find((c) => c.id === id) ?? CITIES[0];
}

function TruckDot({
    x1, y1, x2, y2, delay,
}: {
    x1: number; y1: number; x2: number; y2: number; delay: number;
}) {
    const [progress, setProgress] = useState(0);
    const rafRef = useRef<number | null>(null);
    const startRef = useRef<number | null>(null);
    const pauseRef = useRef<ReturnType<typeof setTimeout> | null>(null);
    const initRef = useRef<ReturnType<typeof setTimeout> | null>(null);

    useEffect(() => {
        const duration = 3000 + Math.random() * 2000;

        const run = () => {
            startRef.current = null;
            const step = (ts: number) => {
                if (!startRef.current) startRef.current = ts;
                const p = Math.min((ts - startRef.current) / duration, 1);
                setProgress(p);
                if (p < 1) {
                    rafRef.current = requestAnimationFrame(step);
                } else {
                    setProgress(0);
                    pauseRef.current = setTimeout(run, 900 + Math.random() * 1500);
                }
            };
            rafRef.current = requestAnimationFrame(step);
        };

        initRef.current = setTimeout(run, delay * 1000 + 1200);

        return () => {
            if (initRef.current) clearTimeout(initRef.current);
            if (pauseRef.current) clearTimeout(pauseRef.current);
            if (rafRef.current) cancelAnimationFrame(rafRef.current);
        };
    }, [delay]);

    if (progress <= 0 || progress >= 1) return null;

    const t = progress;
    const arc = Math.sin(Math.PI * t) * 10;
    const mx = x1 + (x2 - x1) * t;
    const my = y1 + (y2 - y1) * t - arc;

    return (
        <g>
            <circle cx={mx} cy={my} r={3} fill="#fbbf24" opacity={0.95} />
            <circle cx={mx} cy={my} r={6.5} fill="none" stroke="#fbbf24" strokeWidth={0.7} opacity={0.3} />
        </g>
    );
}

export default function AlgeriaMap() {
    const [mounted, setMounted] = useState(false);
    useEffect(() => setMounted(true), []);

    return (
        <div className="relative w-full" style={{ maxWidth: 600 }}>
            <div
                className="absolute inset-0 pointer-events-none"
                style={{
                    background:
                        "radial-gradient(ellipse 70% 60% at 50% 40%, rgba(251,191,36,0.07) 0%, transparent 70%)",
                }}
            />

            <svg
                viewBox="120 30 540 555"
                fill="none"
                xmlns="http://www.w3.org/2000/svg"
                className="w-full h-full"
                style={{ overflow: "visible" }}
            >
                <defs>
                    <filter id="mapGlow" x="-5%" y="-5%" width="110%" height="110%">
                        <feGaussianBlur stdDeviation="2" result="blur" />
                        <feMerge>
                            <feMergeNode in="blur" />
                            <feMergeNode in="SourceGraphic" />
                        </feMerge>
                    </filter>
                    <filter id="nodeGlow" x="-100%" y="-100%" width="300%" height="300%">
                        <feGaussianBlur stdDeviation="3.5" result="blur" />
                        <feMerge>
                            <feMergeNode in="blur" />
                            <feMergeNode in="SourceGraphic" />
                        </feMerge>
                    </filter>
                    <filter id="hubGlow" x="-150%" y="-150%" width="400%" height="400%">
                        <feGaussianBlur stdDeviation="5" result="blur" />
                        <feMerge>
                            <feMergeNode in="blur" />
                            <feMergeNode in="blur" />
                            <feMergeNode in="SourceGraphic" />
                        </feMerge>
                    </filter>
                    <linearGradient id="mapFill" x1="0" y1="0" x2="0.3" y2="1">
                        <stop offset="0%" stopColor="#1c2a4a" />
                        <stop offset="100%" stopColor="#0b1520" />
                    </linearGradient>
                    <linearGradient id="routeAmber" x1="0" y1="0" x2="1" y2="0">
                        <stop offset="0%" stopColor="#fbbf24" stopOpacity="0.15" />
                        <stop offset="50%" stopColor="#fbbf24" stopOpacity="0.5" />
                        <stop offset="100%" stopColor="#fbbf24" stopOpacity="0.15" />
                    </linearGradient>
                    <linearGradient id="routeCyan" x1="0" y1="0" x2="1" y2="0">
                        <stop offset="0%" stopColor="#22d3ee" stopOpacity="0.1" />
                        <stop offset="50%" stopColor="#22d3ee" stopOpacity="0.4" />
                        <stop offset="100%" stopColor="#22d3ee" stopOpacity="0.1" />
                    </linearGradient>
                </defs>

                {/* Real Algeria paths — fill only first (main outline), rest are wilaya borders */}
                {ALGERIA_PATHS.map((d, i) => (
                    <path
                        key={i}
                        d={d}
                        fill={[0, 8, 19, 22, 43].find(ind => ind === i) !== undefined ? "url(#mapFill)" : "none"}
                        stroke={[0, 8, 19, 22, 43].find(ind => ind === i) !== undefined ? "rgba(251,191,36,0.3)" : "rgba(251,191,36,0.18)"}
                        strokeWidth={[0, 8, 19, 22, 43].find(ind => ind === i) !== undefined ? "0.9" : "0.6"}
                        strokeLinecap="round"
                        strokeLinejoin="round"
                        filter={[0, 8, 19, 22, 43].find(ind => ind === i) !== undefined ? "url(#mapGlow)" : undefined}
                    />
                ))}

                {/* Delivery routes — only draw lines between correct city pairs, no external lines */}
                {ROUTES.map((route, i) => {
                    const from = getCityPos(route.from);
                    const to = getCityPos(route.to);
                    const dx = to.x - from.x;
                    const dy = to.y - from.y;
                    const dist = Math.sqrt(dx * dx + dy * dy);
                    // perpendicular offset for gentle curve
                    const nx = -dy / dist;
                    const ny = dx / dist;
                    const bend = dist * 0.12 * (i % 2 === 0 ? 1 : -1);
                    const cx = (from.x + to.x) / 2 + nx * bend;
                    const cy = (from.y + to.y) / 2 + ny * bend;
                    const isAmber = i % 2 === 0;

                    return (
                        <path
                            key={`route-${i}`}
                            d={`M ${from.x} ${from.y} Q ${cx} ${cy} ${to.x} ${to.y}`}
                            stroke={isAmber ? "rgba(251,191,36,0.38)" : "rgba(34,211,238,0.28)"}
                            strokeWidth="1.1"
                            fill="none"
                            strokeLinecap="round"
                        />
                    );
                })}

                {/* Animated truck dots */}
                {mounted &&
                    ROUTES.map((route, i) => {
                        const from = getCityPos(route.from);
                        const to = getCityPos(route.to);
                        return (
                            <TruckDot
                                key={`truck-${i}`}
                                x1={from.x} y1={from.y}
                                x2={to.x} y2={to.y}
                                delay={route.delay}
                            />
                        );
                    })}

                {/* City nodes */}
                {CITIES.map((city) => {
                    const isHub = city.hub;
                    const color = isHub ? "#fbbf24" : "#22d3ee";
                    const r = isHub ? 5 : 2.5;

                    return (
                        <g key={city.id} filter={isHub ? "url(#hubGlow)" : "url(#nodeGlow)"}>
                            {isHub && (
                                <>
                                    <circle cx={city.x} cy={city.y} r={12} fill="none"
                                        stroke="rgba(251,191,36,0.18)" strokeWidth="1"
                                        style={{ animation: "ping2 2s ease-out infinite", transformOrigin: `${city.x}px ${city.y}px` }} />
                                    <circle cx={city.x} cy={city.y} r={20} fill="none"
                                        stroke="rgba(251,191,36,0.07)" strokeWidth="1"
                                        style={{ animation: "ping2 2s ease-out 0.7s infinite", transformOrigin: `${city.x}px ${city.y}px` }} />
                                </>
                            )}
                            <circle cx={city.x} cy={city.y} r={r} fill={color} opacity={0.95} />
                            <circle cx={city.x} cy={city.y} r={r * 0.38} fill="white" opacity={0.9} />
                            {isHub && (
                                <text
                                    x={city.x + r + 6}
                                    y={city.y + 4}
                                    fill="rgba(251,191,36,0.9)"
                                    fontSize="8"
                                    fontFamily="JetBrains Mono, monospace"
                                    fontWeight="600"
                                    letterSpacing="0.5"
                                >
                                    {city.name.toUpperCase()}
                                </text>
                            )}
                        </g>
                    );
                })}
            </svg>


        </div>
    );
}